cat > Makefile << 'EOF'
.PHONY: report clean check-config

# Main target to generate the monitoring report
report: check-config results/status.json
	@echo "Monitoring report complete: results/status.json"

# Check if hosts.conf exists before proceeding
check-config:
	@if [ ! -f hosts.conf ]; then \
		echo "ERROR: hosts.conf is missing. Cannot proceed with monitoring checks."; \
		exit 1; \
	fi

# Create results directory if needed
results:
	@mkdir -p results

# Run ping checks
results/ping.txt: check-config results
	@echo "Running ping checks..."
	@bash scripts/check_ping.sh

# Run port checks
results/ports.txt: check-config results
	@echo "Running port checks..."
	@bash scripts/check_ports.sh

# Generate aggregated JSON report
results/status.json: results/ping.txt results/ports.txt
	@echo "Aggregating results..."
	@python3 aggregate.py

# Clean up generated files
clean:
	@rm -rf results
	@echo "Cleaned up results directory"
EOF

